class InMemoryQueue {
  constructor() {
    this.messages = [];
    this.subscribers = [];
  }

  // Adds a new message to the end of the queue
  publish(payload, ttl = null) {
    const id = uuid(); // generate a unique ID for the message
    const message = { id, payload, ttl };
    this.messages.push(message);
    this.notifySubscribers(); // notify subscribers of new message
  }

  // Retrieves messages from the front of the queue
  pull(maxMessages = 1) {
    const messages = [];
    let i = 0;
    while (i < maxMessages && this.messages.length > 0) {
      const message = this.messages[0];
      if (!message.ttl || message.ttl > Date.now()) {
        messages.push(message);
        this.messages.shift(); // remove message from queue
        i++;
      } else {
        // remove expired message
        this.messages.shift();
      }
    }
    return messages;
  }

  // Adds a new subscriber to the queue
  subscribe(subscriber) {
    this.subscribers.push(subscriber);
  }

  // Notifies all subscribers of new messages
  notifySubscribers() {
    const messages = this.pull(); // get all available messages
    if (messages.length > 0) {
      this.subscribers.forEach(subscriber => subscriber(messages));
    }
  }
}
